UPDATE livreur_workflows SET steps = $JSON$[{"id": "fvdfh3zh", "name": "Authentification Olivraison", "type": "http", "retry": {"backoff_ms": 500, "max_attempts": 3}, "config": {"url": "https://partners.olivraison.com/auth/login", "body": {"apiKey": "{{$secret.OLIVRAISON_API_KEY}}", "secretKey": "{{$secret.OLIVRAISON_SECRET_KEY}}"}, "method": "POST", "headers": {"Content-Type": "application/json"}}, "enabled": true}, {"id": "me9ahh6j", "name": "Sauvegarder le token", "type": "set_variable", "config": {"values": {"token": "{{steps.auth.token}}"}}, "enabled": true}, {"id": "imxyhvyv", "name": "Trouver les commandes à interroger", "type": "find_active_orders", "config": {"limit": 200, "tracking_field": "external_tracking_number", "exclude_statuses": ["Crée", "Confirmé", "Pickup"], "require_tracking": true}, "enabled": true}, {"id": "1lze01hl", "name": "Stop si aucune commande", "type": "filter", "config": {"mode": "all", "on_false": "stop", "conditions": [{"left": "{{steps.find_orders.0.id}}", "operator": "exists"}]}, "enabled": true}, {"id": "bc7vomp9", "name": "Pour chaque commande", "type": "for_each", "config": {"items": "{{steps.find_orders}}", "steps": [{"id": "detail", "name": "GET /package/{tracking}", "type": "http", "retry": {"backoff_ms": 500, "max_attempts": 2}, "config": {"url": "https://partners.olivraison.com/package/{{item.external_tracking_number}}", "method": "GET", "headers": {"Authorization": "Bearer {{vars.token}}"}, "continue_on_error": true}, "enabled": true, "on_error": "continue"}, {"id": "guard_detail", "name": "Stop si pas de history", "type": "filter", "config": {"mode": "all", "on_false": "stop", "conditions": [{"left": "{{steps.detail.history.last.status}}", "operator": "exists"}]}, "enabled": true}, {"id": "map_status", "name": "Mapper statut Olivraison → ODiT", "type": "map_value", "config": {"value": "{{steps.detail.history.last.status}}", "mapping": {"ASSIGN": "ASSIGN", "DELETED": "Annulé", "ENROUTE": "En route", "REFUSED": "Refusé", "